let out = null;
let errMsg = null;
try {
  const data = $json || {};
  let text = '';
  let provider = 'unknown';
  let model = '';
  if (data.content && Array.isArray(data.content) && data.content[0] && data.content[0].text) {
    text = data.content[0].text; provider = 'claude'; model = data.model || '';
  } else if (data.choices && Array.isArray(data.choices) && data.choices[0] && data.choices[0].message && data.choices[0].message.content) {
    text = data.choices[0].message.content; provider = 'hf'; model = data.model || '';
  } else if (data.error) {
    const em = typeof data.error === 'string' ? data.error : (data.error.message || JSON.stringify(data.error));
    throw new Error('Provider error: ' + String(em).slice(0, 300));
  } else {
    throw new Error('Unrecognized LLM response: ' + JSON.stringify(data).slice(0, 200));
  }
  let s = String(text || '').trim();
  s = s.replace(/^```(?:json)?\s*\n?/i, '').replace(/\n?```\s*$/g, '').trim();
  const startObj = s.indexOf('{');
  const startArr = s.indexOf('[');
  let start;
  if (startObj === -1) start = startArr;
  else if (startArr === -1) start = startObj;
  else start = Math.min(startObj, startArr);
  if (start === -1) throw new Error('No JSON found: ' + s.slice(0, 200));
  const lastObj = s.lastIndexOf('}');
  const lastArr = s.lastIndexOf(']');
  const end = Math.max(lastObj, lastArr);
  if (end <= start) throw new Error('Unbalanced JSON: ' + s.slice(0, 200));
  out = JSON.parse(s.slice(start, end + 1));
  if (!out || typeof out !== 'object') throw new Error('Parsed result is not an object');
  if (!Array.isArray(out.questions)) throw new Error('Missing questions array');
  out.quizId = 'q_' + Date.now();
  out._provider = provider;
  out._model = model;
} catch (e) {
  errMsg = (e && e.message) ? e.message : String(e);
}
if (errMsg) return [{ json: { error: errMsg } }];
return [{ json: out }];

const data = $json || {};
let msg = 'diagnostic-generate: AI generation failed';
if (data.error) {
  if (typeof data.error === 'string') msg = data.error;
  else if (data.error.message) msg = data.error.message;
  else msg = JSON.stringify(data.error).slice(0, 300);
} else if (data.message) msg = data.message;
return [{ json: { error: msg } }];

const p = ($json && $json.body) || $json || {};
const questions = Array.isArray(p.questions) ? p.questions : [];
const answers = Array.isArray(p.answers) ? p.answers : [];
const byId = Object.fromEntries(answers.map(a => [a && a.questionId, a && a.chosenIndex]));
const skillCounts = {};
let correct = 0;
for (const q of questions) {
  const skill = (q && q.skill) || 'General';
  skillCounts[skill] = skillCounts[skill] || { correct: 0, total: 0 };
  skillCounts[skill].total += 1;
  const c = byId[q && q.id];
  if (c !== undefined && c === q.correctIndex) { correct += 1; skillCounts[skill].correct += 1; }
}
const total = Math.max(1, questions.length);
const score = Math.round((correct / total) * 100);
const skills = {};
Object.entries(skillCounts).forEach(([k, v]) => { skills[k] = Math.round((v.correct / Math.max(1, v.total)) * 100); });
const skillsLine = Object.entries(skills).map(([k, v]) => k + ': ' + v + '%').join(', ');
const system = [
  'You are Sheldon, analysing a diagnostic test result for the parent and tutor.',
  '',
  'Given per-skill scores, write:',
  '- 2-3 STRENGTHS (specific, encouraging, max 12 words each)',
  '- 2-3 WEAKNESSES (specific but kind. Never use "weak" or "bad". Say "needs more practice with...")',
  '- 3-4 RECOMMENDATIONS (concrete, time-bounded, max 15 words each)',
  '- One ANALYSIS paragraph (3-4 sentences, warm tutor voice, references actual skills/scores)',
  '',
  'Return ONLY valid JSON. No prose before or after. No markdown fences. Shape:',
  '{ "strengths": ["..."], "weaknesses": ["..."], "recommendations": ["..."], "analysisText": "..." }'
].join('\n');
const user = [
  'Quiz id: ' + (p.quizId || ''),
  'Overall score: ' + score + '% (' + correct + '/' + total + ')',
  'Per-skill scores: ' + skillsLine
].join('\n');
return [{ json: { system, user, _payload: p, _score: score, _skills: skills, _kind: 'diagnostic-analyze' } }];

